static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 64;

static inline uint32_t AlignDown(uint32_t x, uint32_t a) { return (x / a) * a; }
static inline uint32_t CeilDiv(uint32_t a, uint32_t b) { return (a + b - 1u) / b; }

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    GemmBiasAddHardtanhMishGroupNormCustomTilingData tiling;

    auto input_shape = context->GetInputShape(0);
    uint32_t batchSize = static_cast<uint32_t>(input_shape->GetOriginShape().GetDim(0));
    uint32_t inFeatures = static_cast<uint32_t>(input_shape->GetOriginShape().GetDim(1));
    uint32_t outFeatures = static_cast<uint32_t>(context->GetInputShape(1)->GetOriginShape().GetDim(0));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    int64_t numGroups = attrs->GetAttrPointer<int64_t>(0)[0];
    uint32_t numGroupsU = static_cast<uint32_t>(numGroups);

    // Tile outFeatures for UB budget: we need to store intermediate results: MatMul partial, bias, hardtanh, mish, gn buffer.
    // Conservative estimate: need 4 * tileOutFeatures per row. bytes = 16 * tileOutFeatures
    uint32_t maxTile = UB_BUDGET_BYTES / 16;
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    uint32_t tileOutF = maxTile;
    if (outFeatures < tileOutF) tileOutF = AlignDown(outFeatures, ALIGN_ELEMS);
    if (tileOutF == 0) tileOutF = outFeatures;

    // BlockDim: based on number of tiles across outFeatures.
    uint32_t numTiles = CeilDiv(outFeatures, tileOutF);
    uint32_t blockDim = numTiles * batchSize;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;
    context->SetBlockDim(blockDim);

    tiling.set_batchSize(batchSize);
    tiling.set_inFeatures(inFeatures);
    tiling.set_outFeatures(outFeatures);
    tiling.set_tileOutFeatures(tileOutF);
    tiling.set_blockDim(blockDim);
    tiling.set_numGroups(numGroupsU);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *workspace = context->GetWorkspaceSizes(1);
    workspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

